class Solution {
public:
    void moveZeroes(vector<int>& nums) {
        vector<int> nonZeroElements;
        for (int num : nums) {
            if (num != 0) {
                nonZeroElements.push_back(num);
            }
        }
        nonZeroElements.resize(nums.size(), 0);
        nums = nonZeroElements;
    }
