    public void moveZeroes(int[] nums) {
        int lastNonZeroPosition = 0;
        for (int i = 0; i < nums.length; i++) {
            if (nums[i] != 0) {
                // Swap the elements
                int temp = nums[i];
                nums[i] = nums[lastNonZeroPosition];
                nums[lastNonZeroPosition] = temp;
                lastNonZeroPosition++;
            }
        }
    }
}

